/** Build a consolidated metadata object for a title by merging Wonder fields with EMA avails data.
 *  Overlapping fields are auto-populated from the first avail record. */
function buildMetadataFromAvails(title) {
  const avail = title.avails?.[0] || {};
  const meta = {};
  wonderMetadataFields.forEach((f) => {
    if (f.ema && avail[f.ema]) {
      meta[f.key] = avail[f.ema];
    } else {
      meta[f.key] = title.metadata?.[f.key] || "";
    }
  });
  /* Always sync identity fields from title-level data */
  meta.content_type = meta.content_type || title.contentType || "";
  meta.reference_id = meta.reference_id || title.refId || "";
  meta.name = meta.name || title.title || "";
  meta.licensor = meta.licensor || title.licensor || "";
  meta.license_start_date = meta.license_start_date || title.startDate || "";
  meta.license_end_date = meta.license_end_date || title.endDate || "";
  return meta;
}

